<span class="line">    s3_client <span class="token operator">=</span> boto3<span class="token punctuation">.</span>client<span class="token punctuation">(</span><span class="token string">&#39;s3&#39;</span><span class="token punctuation">,</span> region_name<span class="token operator">=</span>os<span class="token punctuation">.</span>environ<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&#39;AWS_REGION_NAME&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># your default region</span></span>
