<span class="line"><span class="token keyword">if</span> AWS_LAMBDA_RUNTIME_API <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span> load_dotenv<span class="token punctuation">(</span>override<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">)</span></span>
